class Shape {
public:
    virtual double getArea() = 0;
    virtual ~Shape() {}
};

class Circle : public Shape {
private:
    double radius;
public:
    Circle(double r) : radius(r) {}
    double getArea() override {
        return 3.14159 * radius * radius;
    }
};

void printArea(Shape *s) {
    cout << "Area: " << s->getArea() << endl;
}

int main() {
    Circle c(5);
    printArea(&c);
    return 0;
}

#include <iostream>
using namespace std;

template<typename T>
T add(T a, T b) {
    return a + b;
}

template<typename T>
class Stack {
private:
    T arr[100];
    int top;
public:
    Stack() : top(-1) {}
    void push(T x) { arr[++top] = x; }
    T pop() { return arr[top--]; }
};

int main() {
    cout << add(1, 2) << endl;
    cout << add(1.5, 2.5) << endl;

    Stack<int> s;
    s.push(10);
    s.push(20);
    cout << s.pop() << endl;
    return 0;
}

