#include <iostream>
#include <stdexcept>
using namespace std;

int divide(int a, int b) {
    if (b == 0) {
        throw runtime_error("Division by zero");
    }
    return a / b;
}

int main() {
    try {
        cout << divide(10, 0) << endl;
    } catch (const runtime_error &e) {
        cout << "Error: " << e.what() << endl;
    } catch (...) {
        cout << "Unknown error" << endl;
    }
    return 0;
}
